import osimport asyncioimport threadingimport loggingimport sysfrom pathlib import Pathfrom flask import Flask, request, jsonifyfrom tg_messages import get_chat_previewfrom tg_search import search_chats, prepare_search_params, get_chats_infofrom tg_send import send_messages, group_chats_by_account, process_and_send_messages  # <-- ДОБАВЛЕН ИМПОРТimport atexitfrom tg_utils import (    get_all_folders,    update_chat_folders,    execute_telegram_action,    request_code_internal,    verify_code_with_new_client,    shutdown_clients)# ============================================================#  ПРИНУДИТЕЛЬНАЯ НАСТРОЙКА ЛОГИРОВАНИЯ# ============================================================# Очищаем все существующие хендлерыfor handler in logging.root.handlers[:]:    logging.root.removeHandler(handler)# Создаём новый хендлер для вывода в консольconsole_handler = logging.StreamHandler(sys.stdout)console_handler.setLevel(logging.DEBUG)console_handler.setFormatter(    logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s'))# Настраиваем корневой логгерlogging.root.setLevel(logging.DEBUG)logging.root.addHandler(console_handler)# Отключаем слишком подробные логи от Telethonlogging.getLogger('telethon').setLevel(logging.WARNING)# Убеждаемся, что werkzeug логирует всёlogging.getLogger('werkzeug').setLevel(logging.INFO)# Создаём логгер для нашего модуляlogger = logging.getLogger(__name__)print("✅ Логирование настроено!")app = Flask(__name__)BASE_DIR = Path(__file__).resolve().parentSESSION_DIR = BASE_DIR / 'var' / 'session'SESSION_DIR.mkdir(parents=True, exist_ok=True)# Глобальные настройки аккаунтовaccount_configs = {}pending_auth = {}# ============================================================#  ЕДИНСТВЕННЫЙ EVENT LOOP ДЛЯ TELETHON# ============================================================telegram_loop = asyncio.new_event_loop()def _telegram_loop_runner():    asyncio.set_event_loop(telegram_loop)    telegram_loop.run_forever()telegram_thread = threading.Thread(    target=_telegram_loop_runner,    daemon=True,    name="TelegramLoop")telegram_thread.start()def run_async(coro):    """    Выполняет coroutine в единственном event loop.    """    future = asyncio.run_coroutine_threadsafe(        coro,        telegram_loop    )    return future.result()# ===========================================================================#  API ЭНДПОИНТЫ# ===========================================================================@app.route('/api/init', methods=['POST'])def init_accounts():    print("🔵 ВЫЗВАН /api/init")    try:        data = request.json        print(f"🔵 Данные: {data}")        if not data:            return jsonify({'error': 'Нет данных'}), 400        if isinstance(data, dict) and 'items' in data:            accounts = data['items']        elif isinstance(data, list):            accounts = data        else:            return jsonify({'error': 'Неверный формат'}), 400        for acc in accounts:            account_id = str(acc['id'])            account_configs[account_id] = {                'api_id': int(acc['appId']),                'api_hash': acc['appHash'],                'phone': acc['phone'],                'description': acc.get('description', '')            }            print(f"✅ Аккаунт {account_id} зарегистрирован")        return jsonify({'status': 'ok', 'count': len(account_configs)})    except Exception as e:        print(f"🔴 Ошибка: {e}")        return jsonify({'error': str(e)}), 500@app.route('/api/init/status', methods=['GET'])def get_init_status():    print("🔵 ВЫЗВАН /api/init/status")    return jsonify(list(account_configs.keys()))# ============================================================#  ЭНДПОИНТЫ ДЛЯ АВТОРИЗАЦИИ# ============================================================@app.route('/api/session/request_code', methods=['POST'])def request_code_endpoint():    print("🔵 ВЫЗВАН /api/session/request_code")    """    Запрашивает код подтверждения у Telegram.    Поддерживает два формата:    1. 1    2. {"accountId": 1}    """    try:        data = request.json        print(f"🔵 Данные: {data}")        if isinstance(data, int):            account_id = str(data)        elif isinstance(data, dict):            account_id = str(data.get("accountId"))        else:            return jsonify({                "success": False,                "status": "INVALID_REQUEST",                "message": "Неверный формат запроса"            })        if not account_id:            return jsonify({                "success": False,                "status": "ACCOUNT_ID_REQUIRED"            })        config = account_configs.get(account_id)        if config is None:            return jsonify({                "success": False,                "status": "ACCOUNT_NOT_FOUND"            })        session_name = f"account_{account_id}"        result = run_async(            request_code_internal(                phone=config["phone"],                api_id=config["api_id"],                api_hash=config["api_hash"],                session_name=session_name            )        )        print(f"🔵 Результат: {result}")        return jsonify(result)    except Exception as e:        print(f"🔴 Ошибка запроса кода: {e}")        return jsonify({            "success": False,            "status": "INTERNAL_ERROR",            "message": str(e)        })@app.route('/api/session/verify_code', methods=['POST'])def verify_code_endpoint():    print("🔵 ВЫЗВАН /api/session/verify_code")    """    Подтверждает код и завершает авторизацию.    Ожидает: { "tgAccountId": 1, "code": "12345", "password": "optional" }    """    try:        data = request.json        print(f"🔵 Данные: {data}")        account_id = str(data.get('tgAccountId'))        code = data.get('code')        password = data.get('password')        if not account_id:            return jsonify({'error': 'Не указан tgAccountId'}), 400        if not code:            return jsonify({'error': 'Не указан код'}), 400        config = account_configs.get(account_id)        if not config:            return jsonify({'error': f'Аккаунт {account_id} не найден'}), 404        phone = config['phone']        session_name = f"account_{account_id}"        auth = pending_auth.get(account_id)        if auth is None:            return jsonify({                "success": False,                "status": "CODE_EXPIRED"            })        result = run_async(            verify_code_with_new_client(                account_id=account_id,                phone=auth["phone"],                code=code,                phone_code_hash=auth["phone_code_hash"],                password=password,                api_id=config["api_id"],                api_hash=config["api_hash"],                session_name=f"account_{account_id}"            )        )        print(f"🔵 Результат верификации: {result}")        if result.get('status') == 'success':            pending_auth.pop(account_id, None)            return jsonify({                'status': 'success',                'message': 'Аккаунт успешно авторизован'            })        elif result.get('status') == 'password_required':            return jsonify({                'status': 'password_required',                'message': 'Требуется пароль двухфакторной аутентификации'            }), 400        else:            return jsonify(result), 400    except Exception as e:        print(f"🔴 Ошибка верификации кода: {e}")        return jsonify({'error': str(e)}), 500# ============================================================#  ОСТАЛЬНЫЕ ЭНДПОИНТЫ# ============================================================@app.route('/api/search', methods=['POST'])def search():    print("🔵 ВЫЗВАН /api/search")    try:        data = request.json        print(f"🔵 Данные: {data}")        tg_accounts = data.get('tgAccounts', [])        if not tg_accounts:            return jsonify([]), 400        params = prepare_search_params(data)        print(f"🔵 Параметры поиска: {params}")        all_results = []        for account in tg_accounts:            account_id = str(account) if not isinstance(account, dict) else str(account.get('id'))            if account_id not in account_configs:                continue            found_chats = run_async(                execute_telegram_action(account_id, account_configs, search_chats, params)            )            for chat in found_chats:                chat['tgAccountId'] = account_id                chat['accountPhone'] = account_configs[account_id]['phone']            all_results.extend(found_chats)        print(f"🔵 Найдено чатов: {len(all_results)}")        return jsonify(all_results)    except Exception as e:        print(f"🔴 Ошибка поиска: {e}")        return jsonify([]), 500@app.route('/api/chat-preview', methods=['GET', 'POST'])@app.route('/api/chat-preview/', methods=['GET', 'POST'])def chat_preview():    print("🔵 ВЫЗВАН /api/chat-preview")    try:        if request.method == 'GET':            chat_id = request.args.get('chatId')            account_id = request.args.get('accountId')            limit = request.args.get('limit', default=None, type=int)            print(f"🔵 GET параметры: chatId={chat_id}, accountId={account_id}, limit={limit}")        else:            data = request.json            chat_id = data.get('chatId')            account_id = data.get('accountId')            limit = data.get('limit', None)            print(f"🔵 POST данные: {data}")        if not chat_id or not account_id:            return jsonify({'error': 'Не указаны параметры'}), 400        account_id = str(account_id)        if account_id not in account_configs:            return jsonify({'error': 'Аккаунт не инициализирован'}), 400        result = run_async(            execute_telegram_action(account_id, account_configs, get_chat_preview, int(chat_id), limit)        )        return jsonify(result)    except Exception as e:        print(f"🔴 Ошибка preview: {e}")        return jsonify({'messages': []}), 500@app.route('/api/send_bulk_messages', methods=['POST'])def send_bulk_messages():    print("🔵 ВЫЗВАН /api/send_bulk_messages")    try:        data = request.json        print(f"🔵 Получены данные: {data}")        result = run_async(            process_and_send_messages(                data,                run_async,                account_configs,                execute_telegram_action            )        )        if result.get('error'):            return jsonify({'error': result['error']}), 400        return jsonify(result)    except Exception as e:        print(f"❌ Ошибка: {e}")        import traceback        traceback.print_exc()        return jsonify({'error': str(e)}), 500@app.route('/api/chats/all', methods=['GET'])def get_all_chats():    print("🔵 ВЫЗВАН /api/chats/all")    try:        account_id = str(request.args.get("accountId"))        print(f"🔵 accountId: {account_id}")        if not account_id or account_id not in account_configs:            return jsonify([]), 400        async def get_dialogs(client):            result = []            async for d in client.iter_dialogs():                result.append({                    'id': d.id,                    'name': d.name,                    'username': getattr(d.entity, 'username', None)                })            return result        data = run_async(            execute_telegram_action(account_id, account_configs, get_dialogs)        )        print(f"🔵 Загружено чатов: {len(data)}")        return jsonify(data)    except Exception as e:        print(f"Ошибка: {e}")        return jsonify([]), 500@app.route('/api/folders', methods=['GET', 'POST'])def get_folders():    print("🔵 ВЫЗВАН /api/folders")    try:        if request.method == 'GET':            account_id = request.args.get('accountId')            print(f"🔵 GET accountId: {account_id}")        else:            data = request.json            account_id = data.get('accountId')            print(f"🔵 POST accountId: {account_id}")        if not account_id or account_id not in account_configs:            return jsonify([]), 400        data = run_async(            execute_telegram_action(account_id, account_configs, get_all_folders)        )        return jsonify(data)    except Exception as e:        print(f"Ошибка: {e}")        return jsonify([]), 500@app.route('/api/folders/update', methods=['POST'])def update_folders():    print("🔵 ВЫЗВАН /api/folders/update")    try:        data = request.json        print(f"🔵 Данные: {data}")        account_id = str(data.get('accountId'))        if not account_id or account_id not in account_configs:            return jsonify({'error': 'Не указан accountId'}), 400        folder_id = data.get('folderId')        chat_ids = data.get('chatIds', [])        add_to_folder = data.get('addOperationFlag', True)        if not folder_id or not chat_ids:            return jsonify({'error': 'Не указаны параметры'}), 400        result = run_async(            execute_telegram_action(account_id, account_configs, update_chat_folders, folder_id, chat_ids, add_to_folder)        )        return jsonify(result)    except Exception as e:        print(f"Ошибка: {e}")        return jsonify({'error': str(e)}), 500@app.route('/api/chats/info', methods=['POST'])def get_chats_info_endpoint():    print("🔵 ВЫЗВАН /api/chats/info")    try:        data = request.json        print(f"🔵 Данные: {data}")        account_id = data.get('accountId')        if not account_id or account_id not in account_configs:            return jsonify({'error': 'Не указан accountId'}), 400        chat_ids = data.get('chat_ids', [])        if not chat_ids:            return jsonify({'error': 'Нет ID чатов'}), 400        results = run_async(            execute_telegram_action(account_id, account_configs, get_chats_info, chat_ids)        )        return jsonify(results)    except Exception as e:        print(f"🔴 Ошибка: {e}")        return jsonify({'error': str(e)}), 500def shutdown():    print("Остановка Telegram клиентов...")    future = asyncio.run_coroutine_threadsafe(        shutdown_clients(),        telegram_loop    )    future.result(timeout=10)    telegram_loop.call_soon_threadsafe(        telegram_loop.stop    )    telegram_thread.join(timeout=5)atexit.register(shutdown)if __name__ == '__main__':    print("🚀 Сервер на http://localhost:8081")    app.run(        debug=True,        port=8081    )